// ===== METAPOKE — Détection des nouveautés Drive (tournois) =====
const files = $input.all().map(i=>i.json).filter(f=>f.name && !/DS_Store/.test(f.name));
const sheets = files.filter(f=>(f.mimeType||'').includes('spreadsheet'));
const images = files.filter(f=>(f.mimeType||'').includes('image'));
const pdfs   = files.filter(f=>(f.mimeType||'').includes('pdf'));
const lines=[];
if(sheets.length) lines.push('📊 Sheets modifiés : '+sheets.map(f=>f.name).join(', '));
if(images.length) lines.push('🖼️ Images ajoutées : '+images.map(f=>f.name).join(', '));
if(pdfs.length)   lines.push('📄 PDF ajoutés : '+pdfs.map(f=>f.name).join(', '));
return [{ json: {
  hasChanges: files.length>0,
  nbFichiers: files.length,
  sheetIds: sheets.map(f=>({id:f.id,name:f.name})),
  resume: lines.join('\n') || 'Aucune nouveauté détectée dans le Drive depuis le dernier passage.',
  subject: files.length ? ('METAPOKE Tournois — '+files.length+' nouveauté(s) dans ton Drive') : 'METAPOKE Tournois — rien de neuf'
}}];

