// ===== Parseur feuilles de match — LE SCORE FAIT FOI =====
// Entrée : lignes brutes du Google Sheet. Sortie : matchs au format pbl_matches.json
const rows = $input.all().map(i=>Object.values(i.json));
const CODES='TSM|EX|IMP|XTRP|VIP|US|AKS|TB|FE|AR|IA|SM|XP|AK|RGK';
const matches=[]; let cur=null, session='🕖 19h';
for(const r of rows){
  const cells=r.map(c=>String(c==null?'':c).trim());
  const joined=cells.join(' | ');
  if(/21h/i.test(joined)) session='🕘 21h';
  const vs=joined.match(/\b([A-Za-z]{2,6})\s+vs\s+([A-Za-z]{2,6})\b/i);
  if(vs && !/Decks/i.test(vs[1])){
    cur={a:vs[1].toUpperCase(), b:vs[2].toUpperCase(), session, rounds:[]};
    matches.push(cur); continue;
  }
  const sc=cells.find(c=>/^\d+\s*-\s*\d+$/.test(c));
  if(cur && sc){
    const idx=cells.indexOf(sc);
    const win=cells[idx+1]||'', lose=cells[idx+2]||'';
    if(!win && !lose) continue;
    const m=sc.match(/(\d+)\s*-\s*(\d+)/); const a=+m[1], b=+m[2];
    const prevSc=cur.rounds.length?cur.rounds[cur.rounds.length-1].sc.split('-').map(Number):[0,0];
    // qui a marqué le point ? (le score fait foi, pas la colonne)
    const scorer=(a-prevSc[0]===1 && b===prevSc[1])?cur.a:((b-prevSc[1]===1 && a===prevSc[0])?cur.b:null);
    const tagRe=new RegExp('\\b('+CODES+')\\s*$','i');
    const tag=s=>{const mm=String(s).match(tagRe); return mm?mm[1].toUpperCase():null;};
    let wd=win.replace(tagRe,'').trim(), ld=lose.replace(tagRe,'').trim();
    let wt=tag(win)||scorer, lt=tag(lose);
    if(scorer && wt && wt!==scorer){ const t=wd; wd=ld; ld=t; wt=scorer; lt=(scorer===cur.a?cur.b:cur.a); }
    if(!wt) wt=scorer||cur.a;
    if(!lt) lt=(wt===cur.a?cur.b:cur.a);
    cur.rounds.push({m:'M'+(cur.rounds.length+1), wd, wt, ld, lt, sc:a+'-'+b});
  }
}
const valides=matches.filter(mt=>mt.rounds.length>0);
return [{ json:{ matches:valides, nbMatches:valides.length, sheetName: $json.name||'' } }];
